@using sv_0108c87b6d854a6ab46908b739ed8bff.Models

<div class="step-indicator d-flex align-items-center justify-content-center mb-4">
    @for (var i = 0; i < StepNames.Count; i++)
    {
        var step = i + 1;
        var isActive = step == CurrentStep;
        var isCompleted = CompletedSteps.Contains(step) && !isActive;
        var cssClass = isActive ? "active" : isCompleted ? "completed" : "pending";

        @if (i > 0)
        {
            <div class="step-connector @(CompletedSteps.Contains(step) || isActive ? "filled" : "")"></div>
        }

        <div class="step @cssClass"
             role="button"
             @onclick="() => HandleClick(step)">
            <div class="step-circle">
                @if (isCompleted)
                {
                    <span>✓</span>
                }
                else
                {
                    <span>@step</span>
                }
            </div>
            <div class="step-label">@StepNames[i]</div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public List<string> StepNames { get; set; } = [];
    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public HashSet<int> CompletedSteps { get; set; } = [];
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private async Task HandleClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

.step-indicator {
    gap: 0;
    flex-wrap: nowrap;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    min-width: 90px;
    cursor: default;
    opacity: 0.4;
    transition: opacity 0.2s;
}

.step.active {
    opacity: 1;
}

.step.completed {
    opacity: 1;
    cursor: pointer;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.9rem;
    border: 2px solid #dee2e6;
    background: #fff;
    color: #6c757d;
    transition: all 0.2s;
}

.step.active .step-circle {
    border-color: #0d6efd;
    background: #0d6efd;
    color: #fff;
}

.step.completed .step-circle {
    border-color: #198754;
    background: #198754;
    color: #fff;
}

.step-label {
    margin-top: 6px;
    font-size: 0.75rem;
    text-align: center;
    white-space: nowrap;
    color: #6c757d;
}

.step.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step.completed .step-label {
    color: #198754;
}

.step-connector {
    flex: 1;
    height: 2px;
