arguments.file_text:
@using sv_0108c87b6d854a6ab46908b739ed8bff.Models
@using sv_0108c87b6d854a6ab46908b739ed8bff.Services
@inject IApplicationService ApplicationService

<div class="card">
    <div class="card-body">
        <h3 class="card-title mb-4">Personal Information</h3>

        <div class="mb-3">
            <label class="form-label">Full Name *</label>
            <input class="form-control" @bind="Model.Personal.FullName" @bind:event="oninput" />
        </div>

        <div class="mb-3">
            <label class="form-label">Email *</label>
            <input type="email"
                   class="form-control @(emailError is not null ? "is-invalid" : "")"
                   @bind="Model.Personal.Email" @bind:event="oninput" />
            @if (emailError is not null)
            {
                <div class="invalid-feedback">@emailError</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label">Phone *</label>
            <input type="tel" class="form-control" @bind="Model.Personal.Phone" @bind:event="oninput" />
        </div>

        <div class="mb-3">
            <label class="form-label">Address *</label>
            <textarea class="form-control" rows="2" @bind="Model.Personal.Address" @bind:event="oninput"></textarea>
        </div>

        @if (validationError is not null)
        {
            <div class="alert alert-danger">@validationError</div>
        }

        <div class="d-flex justify-content-end">
            <button type="button" class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
                @if (isValidating)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Next
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ApplicationFormModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }

    private string? validationError;
    private string? emailError;
    private bool isValidating;

    private async Task HandleNext()
    {
        validationError = null;
        emailError = null;

        if (string.IsNullOrWhiteSpace(Model.Personal.FullName) ||
            string.IsNullOrWhiteSpace(Model.Personal.Email) ||
            string.IsNullOrWhiteSpace(Model.Personal.Phone) ||
            string.IsNullOrWhiteSpace(Model.Personal.Address))
        {
            validationError = "All fields are required.";
            return;
        }

        isValidating = true;
        try
        {
            var isValid = await ApplicationService.ValidateEmailAsync(Model.Personal.Email);
            if (!isValid)
            {
                emailError = "Please enter a valid email address.";
                return;
            }
        }
        finally
        {
            isValidating = false;
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_0108c87b6d854a6ab46908b739ed8bff.Models

<div class="card">
    <div class="card-body">
        <h3 class="card-title mb-4">Work History</h3>

        @for (var i = 0; i < Model.WorkEntries.Count; i++)
        {
            var index = i;
            <WorkEntryEditor Model="Model.WorkEntries[index]"
                             Index="index"
                             CanRemove="Model.WorkEntries.Count > 1"
                             OnRemove="() => RemoveEntry(index)" />
        }

        <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
            + Add Another Position
        </button>

        @if (validationError is not null)
        {
            <div class="alert alert-danger">@validationError</div>
        }

        <div class="d-flex justify-content-between">
            <button type="button" class="btn btn-secondary" @onclick="OnBack">Back</button>
            <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ApplicationFormModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? validationError;

    private void AddEntry() => Model.WorkEntries.Add(new());

    private void RemoveEntry(int index) => Model.WorkEntries.RemoveAt(index);

    private async Task HandleNext()
    {
        validationError = null;

        foreach (var entry in Model.WorkEntries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) ||
                string.IsNullOrWhiteSpace(entry.Title) ||
                entry.StartDate is null)
            {
                validationError = "Each position requires a company name, job title, and start date.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_0108c87b6d854a6ab46908b739ed8bff.Models

<div class="card">
    <div class="card-body">
        <h3 class="card-title mb-4">References</h3>

        @for (var i = 0; i < Model.References.Count; i++)
        {
            var index = i;
            <ReferenceEditor Model="Model.References[index]"
                             Index="index"
                             CanRemove="Model.References.Count > 2"
                             OnRemove="() => RemoveReference(index)" />
        }

        @if (Model.References.Count < 3)
        {
            <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddReference">
                + Add Reference
            </button>
        }

        @if (validationError is not null)
        {
