{"file_text": "@using sv_0108c87b6d854a6ab46908b739ed8bff.Models
@using sv_0108c87b6d854a6ab46908b739ed8bff.Services
@inject IApplicationService ApplicationService

<div class="card">
    <div class="card-body">
        <h3 class="card-title mb-4">Review &amp; Submit</h3>

        @* --- Personal Info --- *@
        <div class="review-section mb-4">
            <div class="d-flex justify-content-between align-items-center">
                <h5>Personal Information</h5>
                <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
            </div>
            <hr class="mt-1" />
            <dl class="row mb-0">
                <dt class="col-sm-3">Name</dt>
                <dd class="col-sm-9">@Model.Personal.FullName</dd>
                <dt class="col-sm-3">Email</dt>
                <dd class="col-sm-9">@Model.Personal.Email</dd>
                <dt class="col-sm-3">Phone</dt>
                <dd class="col-sm-9">@Model.Personal.Phone</dd>
                <dt class="col-sm-3">Address</dt>
                <dd class="col-sm-9">@Model.Personal.Address</dd>
            </dl>
        </div>

        @* --- Work History --- *@
        <div class="review-section mb-4">
            <div class="d-flex justify-content-between align-items-center">
                <h5>Work History</h5>
                <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
            </div>
            <hr class="mt-1" />
            @foreach (var entry in Model.WorkEntries)
            {
                <div class="mb-3">
                    <strong>@entry.Title</strong> at @entry.Company
                    <br />
                    <small class="text-muted">
                        @entry.StartDate?.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </small>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mb-0 mt-1">@entry.Description</p>
                    }
                </div>
            }
        </div>

        @* --- References --- *@
        <div class="review-section mb-4">
            <div class="d-flex justify-content-between align-items-center">
                <h5>References</h5>
                <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
            </div>
            <hr class="mt-1" />
            @foreach (var r in Model.References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> — @r.Relationship
                    <br />
                    <small class="text-muted">@r.Email · @r.Phone</small>
                </div>
            }
        </div>

        @* --- Cover Letter --- *@
        <div class="review-section mb-4">
            <div class="d-flex justify-content-between align-items-center">
                <h5>Cover Letter</h5>
                <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(4)">Edit</button>
            </div>
            <hr class="mt-1" />
            <p style="white-space: pre-wrap;">@Model.CoverLetter</p>
        </div>

        @if (errorMessage is not null)
        {
            <div class="alert alert-danger">@errorMessage</div>
        }

        <div class="d-flex justify-content-between">
            <button type="button" class="btn btn-secondary" @onclick="OnBack">Back</button>
            <button type="button" class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@isSubmitting">
                @if (isSubmitting)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Submit Application
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ApplicationFormModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback<int> OnEdit { get; set; }
    [Parameter] public EventCallback<int> OnSubmitted { get; set; }

    private bool isSubmitting;
    private string? errorMessage;

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        errorMessage = null;

        try
        {
            var applicationId = await ApplicationService.SubmitApplicationAsync(Model.ToRecord());
            await OnSubmitted.InvokeAsync(applicationId);
        }
        catch (Exception ex)
        {
            errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}
