@using sv_0108c87b6d854a6ab46908b739ed8bff.Models

<div class="card">
    <div class="card-body">
        <h3 class="card-title mb-4">Work History</h3>

        @for (var i = 0; i < Model.WorkEntries.Count; i++)
        {
            var index = i;
            <WorkEntryEditor Model="Model.WorkEntries[index]"
                             Index="index"
                             CanRemove="Model.WorkEntries.Count > 1"
                             OnRemove="() => RemoveEntry(index)" />
        }

        <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
            + Add Another Position
        </button>

        @if (validationError is not null)
        {
            <div class="alert alert-danger">@validationError</div>
        }

        <div class="d-flex justify-content-between">
            <button type="button" class="btn btn-secondary" @onclick="OnBack">Back</button>
            <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ApplicationFormModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? validationError;

    private void AddEntry() => Model.WorkEntries.Add(new());

    private void RemoveEntry(int index) => Model.WorkEntries.RemoveAt(index);

    private async Task HandleNext()
    {
        validationError = null;

        foreach (var entry in Model.WorkEntries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) ||
                string.IsNullOrWhiteSpace(entry.Title) ||
                entry.StartDate is null)
            {
                validationError = "Each position requires a company name, job title, and start date.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

