@page "/apply"
@rendermode InteractiveServer
@using sv_0108c87b6d854a6ab46908b739ed8bff.Models
@using sv_0108c87b6d854a6ab46908b739ed8bff.Components.JobApplication

<PageTitle>Job Application</PageTitle>

<div class="container my-4" style="max-width: 800px;">
    <h1 class="mb-4">Job Application</h1>

    @if (isSubmitted)
    {
        <div class="card text-center">
            <div class="card-body py-5">
                <div class="text-success mb-3" style="font-size: 3rem;">✓</div>
                <h2 class="card-title">Application Submitted!</h2>
                <p class="card-text text-muted mt-2">
                    Your application has been received. Your confirmation number is:
                </p>
                <h4 class="text-primary">@applicationId</h4>
            </div>
        </div>
    }
    else
    {
        <StepIndicator StepNames="@stepNames"
                       CurrentStep="currentStep"
                       CompletedSteps="completedSteps"
                       OnStepClicked="GoToStep" />

        @switch (currentStep)
        {
            case 1:
                <PersonalInfoStep Model="model" OnNext="AdvanceStep" />
                break;
            case 2:
                <WorkHistoryStep Model="model" OnNext="AdvanceStep" OnBack="GoBack" />
                break;
            case 3:
                <ReferencesStep Model="model" OnNext="AdvanceStep" OnBack="GoBack" />
                break;
            case 4:
                <CoverLetterStep Model="model" OnNext="AdvanceStep" OnBack="GoBack" />
                break;
            case 5:
                <ReviewStep Model="model"
                            OnBack="GoBack"
                            OnEdit="GoToStep"
                            OnSubmitted="HandleSubmitted" />
                break;
        }
    }
</div>

@code {
    private readonly List<string> stepNames =
    [
        "Personal Info",
        "Work History",
        "References",
        "Cover Letter",
        "Review & Submit"
    ];

    private readonly ApplicationFormModel model = new();
    private readonly HashSet<int> completedSteps = [];

    private int currentStep = 1;
    private bool isSubmitted;
    private int applicationId;

    private void AdvanceStep()
    {
        completedSteps.Add(currentStep);
        if (currentStep < stepNames.Count)
            currentStep++;
    }

    private void GoBack()
    {
        if (currentStep > 1)
            currentStep--;
    }

    private void GoToStep(int step)
    {
        if (step >= 1 && step <= stepNames.Count)
            currentStep = step;
    }

    private void HandleSubmitted(int id)
    {
        applicationId = id;
        isSubmitted = true;
    }
}

